 1	import * as React from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  Button,
 7	  EmptyState,
 8	  EmptyStateActions,
 9	  EmptyStateBody,
10	  EmptyStateFooter,
11	  EmptyStateHeader,
12	} from '@patternfly/react-core';
13	
14	export const WizardEmptyState: React.FC<{ namespace: string }> = ({ namespace }) => {
15	  const { t } = useKubevirtTranslation();
16	  const navigate = useNavigate();
17	
18	  return (
19	    <EmptyState>
20	      <EmptyStateHeader headingLevel="h4" titleText={<>{t('No Template found')}</>} />
21	      <EmptyStateBody>
22	        {t('No Template was selected for review, please go to the catalog and select one.')}
23	      </EmptyStateBody>
24	      <EmptyStateFooter>
25	        <EmptyStateActions>
26	          <Button onClick={() => navigate(`/k8s/ns/${namespace}/catalog/template`)}>
27	            {t('Go to catalog')}
28	          </Button>
29	        </EmptyStateActions>
30	      </EmptyStateFooter>
31	    </EmptyState>
32	  );
33	};

